code.python:
def missing_number(nums):
    present = set(nums)
    for i in range(len(nums) + 1):
        if i not in present:
            return i
    return -1

code.javascript:
function missingNumber(nums) {
  const present = new Set(nums);
  for (let i = 0; i <= nums.length; i++) {
    if (!present.has(i)) {
      return i;
    }
  }
  return -1;
}

